code = """import json
import pandas as pd
import re

# Load data
clinical_data = locals()['var_functions.query_db:22']
cdh1_data = locals()['var_functions.query_db:38']

if isinstance(clinical_data, str):
    with open(clinical_data, 'r') as f:
        clinical_data = json.load(f)
if isinstance(cdh1_data, str):
    with open(cdh1_data, 'r') as f:
        cdh1_data = json.load(f)

# Process clinical records
bladder_patients = []
for record in clinical_data:
    patient_desc = record['Patient_description']
    match = re.search(r'(TCGA-[A-Z0-9]+-[A-Z0-9]+)', patient_desc)
    if match:
        bladder_patients.append({
            'patient_id': match.group(1),
            'histological_type': record['histological_type']
        })

# Get CDH1 mutated patients
cdh1_patient_ids = set([record['ParticipantBarcode'] for record in cdh1_data])

# Create dataframe
df = pd.DataFrame(bladder_patients)
df['cdh1_mutated'] = df['patient_id'].apply(lambda x: 1 if x in cdh1_patient_ids else 0)

# Analysis details
print("=== FEMALE BLADDER CANCER ANALYSIS ===")
print("Total patients:", len(df))
print("CDH1 mutations:", df['cdh1_mutated'].sum())
print("Mutation rate:", round(df['cdh1_mutated'].sum() / len(df) * 100, 2), "%")
print("Histological types:", df['histological_type'].nunique())
print("Primary histological type:", df['histological_type'].mode()[0])

# Contingency table
contingency = pd.crosstab(df['histological_type'], df['cdh1_mutated'])
contingency.columns = ['No_Mutation', 'Mutation']
print("\nContingency table:")
print(contingency)

result = {
    "chi_square_statistic": "Not applicable - single histological category",
    "total_female_bladder_patients": len(df),
    "bladder_patients_with_cdh1_mutation": int(df['cdh1_mutated'].sum()),
    "mutation_rate_percent": round(df['cdh1_mutated'].sum() / len(df) * 100, 2),
    "histological_category": df['histological_type'].mode()[0] if len(df) > 0 else "None",
    "unique_histological_types": df['histological_type'].nunique(),
    "note": "Only one histological type present after filtering - chi-square test requires at least 2 categories"
}

print("__RESULT__:")
print(json.dumps(result))"""

